package com.sap.ec.core.channel

import com.sap.ec.api.SdkState
import com.sap.ec.context.SdkContextApi
import com.sap.ec.core.Registerable
import com.sap.ec.core.db.events.EventsDaoApi
import com.sap.ec.core.log.LogEventRegistryApi
import com.sap.ec.core.log.Logger
import com.sap.ec.event.OnlineSdkEvent
import com.sap.ec.api.event.model.EngagementCloudEvent
import com.sap.ec.event.SdkEvent
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.CoroutineStart
import kotlinx.coroutines.channels.Channel
import kotlinx.coroutines.currentCoroutineContext
import kotlinx.coroutines.ensureActive
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.flow.filter
import kotlinx.coroutines.flow.filterIsInstance
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.flow.merge
import kotlinx.coroutines.flow.onEach
import kotlinx.coroutines.launch
import kotlinx.serialization.json.buildJsonObject
import kotlinx.serialization.json.put

internal class SdkEventDistributor(
    private val connectionStatus: StateFlow<Boolean>,
    private val sdkContext: SdkContextApi,
    private val eventsDao: EventsDaoApi,
    private val logEventRegistry: LogEventRegistryApi,
    private val applicationScope: CoroutineScope,
    private val sdkLogger: Logger
) : SdkEventManagerApi, Registerable {

    private val _sdkEventFlow = MutableSharedFlow<SdkEvent>(
        replay = 100,
        extraBufferCapacity = Channel.UNLIMITED
    )

    private val _sdkPublicEventFlow = MutableSharedFlow<EngagementCloudEvent>(
        replay = 100,
        extraBufferCapacity = Channel.UNLIMITED
    )

    override val sdkPublicEventFlow = _sdkPublicEventFlow.asSharedFlow()

    override val sdkEventFlow = _sdkEventFlow.asSharedFlow()

    private val _onlineSdkEvents: Flow<OnlineSdkEvent> =
        _sdkEventFlow
            .filterIsInstance<OnlineSdkEvent>()
            .filter { it !is SdkEvent.Internal.LogEvent }
            .onEach { connectionStatus.first { it } }

    /**
     * Events that have the [SdkEvent.Internal.OperationalEvent] interface are processed even when the SDK is below OnHold state.
     */
    private val operationalOnlineEvents =
        _onlineSdkEvents
            .filterIsInstance<SdkEvent.Internal.OperationalEvent>()

    /**
     * Events that have the [SdkEvent.Internal.SetupFlowEvent] interface are processed when the SDK is in OnHold or Active state.
     * This is needed as some events related to the setup flow (e.g. [SdkEvent.Internal.Sdk.RegisterDeviceInfo]) need to be processed even when the SDK is in OnHold state.
     */
    private val setupFlowOnlineEvents =
        _onlineSdkEvents
            .filterIsInstance<SdkEvent.Internal.SetupFlowEvent>()
            .onEach { sdkContext.currentSdkState.first { it == SdkState.Active || it == SdkState.OnHold } }

    /**
     * All other events are processed only when the SDK is in Active state.
     */
    private val activeStateOnlineEvents =
        _onlineSdkEvents
            .filter { it !is SdkEvent.Internal.SetupFlowEvent && it !is SdkEvent.Internal.OperationalEvent }
            .onEach { sdkContext.currentSdkState.first { it == SdkState.Active } }

    override val onlineSdkEvents: Flow<OnlineSdkEvent> =
        merge(operationalOnlineEvents, setupFlowOnlineEvents, activeStateOnlineEvents)

    override val logEvents = _sdkEventFlow
        .filterIsInstance<SdkEvent.Internal.LogEvent>()
        .onEach {
            connectionStatus.first { it }
        }

    override suspend fun register() {
        applicationScope.launch(start = CoroutineStart.UNDISPATCHED) {
            sdkLogger.debug("Register")
            logEventRegistry.logEvents
                .collect {
                    registerEvent(it)
                }
        }
    }

    /**
     * Registers an [SdkEvent] by persisting [OnlineSdkEvent] instances to the database and
     * emitting the event to the SDK event flow. Returns an [SdkEventWaiterApi] that can be
     * used to await a response event matching the original event's id.
     *
     * Events implementing [OnlineSdkEvent] are stored in the database so they survive app
     * restarts and can be retried. Non-[OnlineSdkEvent] events are emitted to the flow
     * without persistence.
     */
    override suspend fun registerEvent(sdkEvent: SdkEvent): SdkEventWaiterApi {
        return try {
            if (sdkEvent is OnlineSdkEvent) {
                eventsDao.insertEvent(sdkEvent)
            }
            _sdkEventFlow.emit(sdkEvent)
            SdkEventWaiter(this@SdkEventDistributor, sdkEvent, connectionStatus)
        } catch (exception: Exception) {
            currentCoroutineContext().ensureActive()
            sdkLogger.error(
                "SdkEventDistributor - Failed to register event",
                exception,
                buildJsonObject { put("event", sdkEvent.toString()) },
                isRemoteLog = sdkEvent !is SdkEvent.Internal.LogEvent
            )
            SdkEventWaiter(
                this@SdkEventDistributor,
                SdkEvent.Internal.Sdk.Answer.Response(
                    sdkEvent.id,
                    Result.failure<Exception>(exception)
                ),
                connectionStatus
            )
        }
    }

    override suspend fun registerPublicEvent(sdkEvent: EngagementCloudEvent) {
        sdkLogger.trace("Register public event: ${sdkEvent.type}", buildJsonObject { put("event", sdkEvent.toString()) })
        _sdkPublicEventFlow.emit(sdkEvent)
    }

    /**
     * Emits an [SdkEvent] directly to the SDK event flow without persisting it to the database.
     *
     * Use this method for local signaling events that do not need to survive app restarts
     * or be retried on failure.
     */
    override suspend fun emitEvent(sdkEvent: SdkEvent) {
        try {
            _sdkEventFlow.emit(sdkEvent)
        } catch (exception: Exception) {
            currentCoroutineContext().ensureActive()
            sdkLogger.error(
                "SdkEventDistributor - Failed to emit event",
                exception,
                buildJsonObject { put("event", sdkEvent.toString()) })
        }
    }
}