package com.sap.ec.api.config

import com.sap.ec.api.Activatable
import com.sap.ec.api.SdkState
import com.sap.ec.api.generic.GenericApi
import com.sap.ec.context.SdkContextApi
import com.sap.ec.core.device.DeviceInfo
import com.sap.ec.core.device.DeviceInfoCollectorApi
import com.sap.ec.core.device.NotificationSettings
import com.sap.ec.core.log.withLogContext
import com.sap.ec.util.runCatchingWithoutCancellation
import kotlinx.coroutines.flow.first
import kotlinx.coroutines.withContext
import kotlinx.serialization.json.JsonPrimitive
import kotlinx.serialization.json.buildJsonObject

internal interface ConfigInstance : ConfigInternalApi, Activatable

internal class Config<Logging : ConfigInstance, Gatherer : ConfigInstance, Internal : ConfigInstance>(
    loggingApi: Logging,
    gathererApi: Gatherer,
    internalApi: Internal,
    sdkContext: SdkContextApi,
    private val deviceInfoCollector: DeviceInfoCollectorApi
) : GenericApi<Logging, Gatherer, Internal>(
    loggingApi,
    gathererApi,
    internalApi,
    sdkContext
), ConfigApi {

    override suspend fun getApplicationCode(): String? {
        return when (sdkContext.currentSdkState.value) {
            SdkState.OnHold -> {
                sdkContext.currentSdkState.first { it == SdkState.Active || it == SdkState.Initialized }
                sdkContext.getSdkConfig()?.applicationCode
            }
            SdkState.UnInitialized, SdkState.Initialized -> null
            SdkState.Active -> sdkContext.getSdkConfig()?.applicationCode
        }
    }

    override suspend fun getClientId(): String = deviceInfoCollector.getClientId()

    override suspend fun getLanguageCode(): String = getDeviceInfo().language

    override suspend fun getApplicationVersion(): String = getDeviceInfo().applicationVersion

    override suspend fun getSdkVersion(): String = getDeviceInfo().sdkVersion

    override suspend fun getCurrentSdkState(): SdkState = sdkContext.currentSdkState.value

    override suspend fun changeApplicationCode(applicationCode: String): Result<Unit> =
        runCatchingWithoutCancellation {
            withContext(sdkContext.sdkDispatcher) {
                withLogContext(buildJsonObject {
                    put(
                        "applicationCode",
                        JsonPrimitive(applicationCode)
                    )
                }) {
                    activeInstance<ConfigInternalApi>().changeApplicationCode(applicationCode)
                }
            }
        }

    override suspend fun setLanguage(language: String): Result<Unit> = runCatchingWithoutCancellation {
        withContext(sdkContext.sdkDispatcher) {
            withLogContext(buildJsonObject {
                put("language", JsonPrimitive(language))
            }) {
                activeInstance<ConfigInternalApi>().setLanguage(language)
            }
        }
    }

    override suspend fun resetLanguage(): Result<Unit> = runCatchingWithoutCancellation {
        withContext(sdkContext.sdkDispatcher) {
            withLogContext(buildJsonObject {}) {
                activeInstance<ConfigInternalApi>().resetLanguage()
            }
        }
    }

    override suspend fun getNotificationSettings(): NotificationSettings {
        return deviceInfoCollector.getNotificationSettings()
    }

    private suspend fun getDeviceInfo(): DeviceInfo {
        return deviceInfoCollector.collectAsDeviceInfo()
    }
}