package com.sap.ec.mobileengage.embeddedmessaging.ui.list

import androidx.paging.Pager
import androidx.paging.PagingConfig
import androidx.paging.PagingData
import com.sap.ec.context.SdkContextApi
import com.sap.ec.core.channel.SdkEventDistributorApi
import com.sap.ec.core.log.Logger
import com.sap.ec.core.networking.context.RequestContextApi
import com.sap.ec.core.util.DownloaderApi
import com.sap.ec.mobileengage.action.ActionFactoryApi
import com.sap.ec.mobileengage.action.models.ActionModel
import com.sap.ec.mobileengage.embeddedmessaging.pagination.EmbeddedMessagingPagingSource
import com.sap.ec.mobileengage.embeddedmessaging.ui.item.MessageItemViewModelApi
import com.sap.ec.networking.clients.embedded.messaging.model.Category
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow

internal class PagerFactory(
    private val model: ListPageModelApi,
    private val downloaderApi: DownloaderApi,
    private val sdkEventDistributor: SdkEventDistributorApi,
    private val actionFactory: ActionFactoryApi<ActionModel>,
    private val sdkContext: SdkContextApi,
    private val logger: Logger,
    private val requestContext: RequestContextApi
) : PagerFactoryApi {
    override fun create(
        filterUnopenedOnly: Boolean,
        selectedCategoryIds: List<String>,
        categories: MutableStateFlow<List<Category>>
    ): Flow<PagingData<MessageItemViewModelApi>> {
        return Pager(
            config = PagingConfig(
                pageSize = -1,  // ignored because it is set by the backend
                prefetchDistance = 2,
                enablePlaceholders = true,
                initialLoadSize = -1,  // also ignored
                maxSize = Int.MAX_VALUE,
            ),
            initialKey = 0,
            pagingSourceFactory = {
                EmbeddedMessagingPagingSource(
                    listPageModel = model,
                    filterUnopenedOnly = filterUnopenedOnly,
                    selectedCategoryIds = selectedCategoryIds.toList(),
                    setCategories = { categories.value = it },
                    downloader = downloaderApi,
                    actionFactory = actionFactory,
                    sdkEventDistributor = sdkEventDistributor,
                    sdkContext = sdkContext,
                    logger = logger,
                    hasContactToken = { requestContext.contactToken != null }
                )
            }
        ).flow
    }

}