sealed interface OnlineSdkEvent : SdkEvent {
    var nackCount: Int

    suspend fun ack(eventsDao: EventsDaoApi, sdkLogger: Logger) {
        try {
            eventsDao.removeEvent(this)
        } catch (exception: Exception) {
            currentCoroutineContext().ensureActive()
            sdkLogger.error(
                "OnlineSdkEvent - ack: error acking OnlineSdkEvent",
                exception,
                buildJsonObject {
                    put("event", this.toString())
                },
                isRemoteLog = this !is SdkEvent.Internal.LogEvent
            )
        }
    }

    suspend fun nack(eventsDao: EventsDaoApi, sdkLogger: Logger) {
        try {
            this.nackCount++
            if (this.nackCount >= 3) {
                eventsDao.removeEvent(this)
            } else {
                eventsDao.upsertEvent(this)
            }
        } catch (exception: Exception) {
            currentCoroutineContext().ensureActive()
            sdkLogger.error(
                "OnlineSdkEvent - nack: error nack OnlineSdkEvent",
                exception,
                buildJsonObject {
                    put("event", this.toString())
                },
                isRemoteLog = this !is SdkEvent.Internal.LogEvent
            )
        }
    }
}

internal suspend fun List<OnlineSdkEvent>.ack(eventsDao: EventsDaoApi, sdkLogger: Logger) {
    this.forEach {
        it.ack(eventsDao, sdkLogger)
    }
}

internal suspend fun List<OnlineSdkEvent>.nack(eventsDao: EventsDaoApi, sdkLogger: Logger) {
    this.forEach {
        it.nack(eventsDao, sdkLogger)
    }
}

@InternalSdkApi
@OptIn(ExperimentalSerializationApi::class, ExperimentalTime::class)
@Serializable
@JsonClassDiscriminator("fullClassName")
sealed interface SdkEvent {
    val id: String
    val type: String
    val timestamp: Instant

    @Serializable
    sealed interface DeviceEvent : SdkEvent {
        val name: String

        fun createAttributesMap(): Map<String, String>?

        fun createDeviceEventFromAttributesMap(attributes: Map<String, String>?): com.sap.ec.networking.clients.event.model.DeviceEvent =
            DeviceEvent(
                type = this.type,
                name = this.name,
                timestamp = this.timestamp,
                attributes = attributes,
                trackingInfo = null,
                reporting = null
            )

        fun toDeviceEvent(
            platformCategory: String = SdkConstants.MOBILE_PLATFORM_CATEGORY,
            pageLocation: String
        ): com.sap.ec.networking.clients.event.model.DeviceEvent {
            val pageLocation = if (platformCategory == SdkConstants.WEB_PLATFORM_CATEGORY) {
                SdkConstants.PAGE_LOCATION_ATTRIBUTE_KEY to pageLocation
            } else null
            val attributesMap = createAttributesMap()
            val extendedAttributesMap: Map<String, String>? =
                if (attributesMap == null && pageLocation == null) null
                else buildMap {
                    attributesMap?.let { putAll(it) }
                    pageLocation?.let { put(it.first, it.second) }
                }
            return createDeviceEventFromAttributesMap(extendedAttributesMap)
        }
    }

    sealed interface DeviceEventWithCustomAttributes : DeviceEvent {
        val attributes: JsonObject?

        override fun createAttributesMap(): Map<String, String>? = buildMap {
            attributes?.forEach { (key, value) ->
                put(key, value.jsonPrimitive.content)
            }
        }
    }

    sealed interface External : SdkEvent {

        @Serializable
        data class Custom(
            override val id: String = UUIDProvider().provide(),
            override val name: String,
            override val attributes: JsonObject? = null,
            override val timestamp: Instant = TimestampProvider().provide(),
            override var nackCount: Int = 0
        ) : External, OnlineSdkEvent, DeviceEventWithCustomAttributes {
            override val type: String = "custom"
        }

        @Serializable
        data class NavigateEvent(
            override val id: String = UUIDProvider().provide(),
            override val timestamp: Instant,
            val location: String,
            override var nackCount: Int = 0
        ) : External, OnlineSdkEvent, DeviceEvent {
            override val type: String = "internal"
            override val name: String = "navigate"

            override fun createAttributesMap(): Map<String, String> = buildMap {
                put("location", location)
            }
        }
    }


