package com.sap.ec.networking.clients.event.model

import com.sap.ec.mobileengage.action.models.BasicActionModel
import com.sap.ec.mobileengage.inapp.InAppMessage
import com.sap.ec.mobileengage.inapp.presentation.InAppType
import kotlinx.serialization.Serializable

@Serializable
internal data class DeviceEventResponse(
    val contentCampaigns: List<ContentCampaign>? = null,
    val actionCampaigns: List<OnEventActionCampaign>? = null,
    val deviceEventState: String? = null
)

@Serializable
internal data class OnEventActionCampaign(
    val trackingInfo: String,
    val actions: List<BasicActionModel>
)

@Serializable
internal data class ContentCampaign(
    val type: InAppType,
    val trackingInfo: String,
    val content: String
)

internal fun ContentCampaign.asInAppMessage(): InAppMessage {
    return InAppMessage(type = this.type, trackingInfo = this.trackingInfo, content = this.content)
}